from llama_index.core import VectorStoreIndex
from llama_index.core.retrievers import VectorIndexRetriever

import re

PII_PATTERNS = [
    r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
    r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',  # Email
    r'\b(sk-\w+|ak-\w+|pk-\w+)\b'  # API keys
]

def scan_retrieved_nodes(nodes):
    leaks = []
    for node in nodes:
        text = node.text
        for pattern in PII_PATTERNS:
            matches = re.finditer(pattern, text)
            for match in matches:
                leaks.append({
                    'node': node.node_id,
                    'text': match.group(),
                    'position': match.span()
                })
    return leaks

import spacy

nlp = spacy.load('en_core_web_sm')

def detect_entities_in_response(response: str):
    doc = nlp(response)
    sensitive_entities = []
    for ent in doc.ents:
        if ent.label_ in ['PERSON', 'ORG', 'GPE']:
            sensitive_entities.append({
                'entity': ent.text,
                'label': ent.label_,
                'confidence': ent._.get('confidence', 1.0)
            })
    return sensitive_entities

