from llama_index.core import VectorStoreIndex, StorageContext
from llama_index.core.node_parser import SentenceSplitter

class SensitiveDataNodeParser(SentenceSplitter):
    PII_PATTERNS = [r'\b\d{3}-\d{2}-\d{4}\b', r'api[_-]?key']

    def _contains_sensitive_data(self, text: str) -> bool:
        return any(re.search(pattern, text) for pattern in self.PII_PATTERNS)

    def get_nodes_from_documents(self, documents):
        nodes = super().get_nodes_from_documents(documents)
        return [n for n in nodes if not self._contains_sensitive_data(n.text)]

# Usage
parser = SensitiveDataNodeParser(chunk_size=512)
index = VectorStoreIndex.from_documents(
    docs, transformations=[parser]
)
